--
-- Table structure for table `TB_CUSTOMER`
--

DROP TABLE IF EXISTS `TB_CUSTOMER`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `TB_CUSTOMER` (
  `CUST_ID` int(11) NOT NULL AUTO_INCREMENT COMMENT '고객 고유번호(PK)',
  `STATUS` varchar(20) DEFAULT '접수' COMMENT '진행상태 (접수, 개통완료, 취소 등)',
  `CUST_NAME` varchar(50) NOT NULL COMMENT '고객명',
  `REP_NAME` varchar(50) DEFAULT NULL COMMENT '대표자명 (사업자/법인인 경우)',
  `CUST_TYPE` varchar(20) DEFAULT NULL COMMENT '고객종류 (개인, 개인사업자, 법인, 미성년자, 외국인)',
  `CUST_KIND` varchar(20) DEFAULT 'INDIVIDUAL' COMMENT '고객구분 (INDIVIDUAL: 개인고객, PARTNER: 협력점고객)',
  `SSN_ENC` varchar(255) DEFAULT NULL COMMENT '주민번호 (암호화)',
  `BIZ_NO` varchar(20) DEFAULT NULL COMMENT '사업자번호',
  `CORP_NO` varchar(20) DEFAULT NULL COMMENT '법인번호',
  `ZIP_CODE` varchar(10) DEFAULT NULL COMMENT '우편번호',
  `ADDR` varchar(255) DEFAULT NULL COMMENT '주소',
  `ADDR_DETAIL` varchar(255) DEFAULT NULL COMMENT '상세주소',
  `TEL_NO` varchar(20) DEFAULT NULL COMMENT '전화번호',
  `HP_NO` varchar(20) DEFAULT NULL COMMENT '핸드폰번호',
  `HP_CARRIER` varchar(20) DEFAULT NULL COMMENT '핸드폰 통신사 (SKT, KT, LGU+ 등)',
  `EMAIL` varchar(100) DEFAULT NULL COMMENT '이메일',
  `CUST_AUTH_TYPE` varchar(50) DEFAULT NULL COMMENT '고객인증 방식',
  `CUST_AUTH_VAL` varchar(100) DEFAULT NULL COMMENT '고객인증 값',
  `COUNSELOR_NAME` varchar(50) DEFAULT NULL COMMENT '상담원명',
  `DEPT_ID` int(11) DEFAULT NULL COMMENT '담당 부서 ID',
  `ASSIGNED_USER_ID` int(11) DEFAULT NULL COMMENT '담당자 ID',
  `REMARK` text DEFAULT NULL COMMENT '비고 (상세 내용)',
  `FILE_GROUP_ID` varchar(36) DEFAULT NULL COMMENT '첨부파일 그룹 ID (UUID)',
  `VOUCHER_RETURN_YN` char(1) DEFAULT 'N' COMMENT '상품권 반환 여부 (Y/N)',
  `USE_YN` char(1) DEFAULT 'Y' COMMENT '사용 여부 (Y/N)',
  `CREATOR_ID` int(11) DEFAULT NULL COMMENT '최초 등록자 ID',
  `CREATED_AT` datetime DEFAULT current_timestamp() COMMENT '등록 일시',
  `UPDATED_AT` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp() COMMENT '수정 일시',
  PRIMARY KEY (`CUST_ID`),
  KEY `FK_CUST_DEPT` (`DEPT_ID`),
  KEY `FK_CUST_USER` (`ASSIGNED_USER_ID`),
  KEY `FK_CUST_FILE_GROUP` (`FILE_GROUP_ID`),
  CONSTRAINT `FK_CUST_DEPT` FOREIGN KEY (`DEPT_ID`) REFERENCES `TB_DEPARTMENT` (`DEPT_ID`),
  CONSTRAINT `FK_CUST_FILE_GROUP` FOREIGN KEY (`FILE_GROUP_ID`) REFERENCES `TB_FILE_GROUP` (`GROUP_ID`),
  CONSTRAINT `FK_CUST_USER` FOREIGN KEY (`ASSIGNED_USER_ID`) REFERENCES `TB_USER` (`USER_ID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_uca1400_ai_ci COMMENT='고객 기본 정보 마스터';
/*!40101 SET character_set_client = @saved_cs_client */;

