LOCK TABLES `TB_CUSTOMER` WRITE;
/*!40000 ALTER TABLE `TB_CUSTOMER` DISABLE KEYS */;
/*!40000 ALTER TABLE `TB_CUSTOMER` ENABLE KEYS */;
UNLOCK TABLES;

