CREATE TABLE `TB_CUST_GIFT` (
  `GIFT_ID` int(11) NOT NULL AUTO_INCREMENT COMMENT '사은품 일련번호 (PK)',
  `CUST_ID` int(11) NOT NULL COMMENT '고객 고유번호 (FK)',
  `GIFT_GB` varchar(20) NOT NULL COMMENT '사은품 구분 (GENERAL: 일반, HEAD: 본사)',
  `GIFT_NAME` varchar(100) DEFAULT NULL COMMENT '사은품 명 (또는 본사사은품 명)',
  `GIFT_AMOUNT` int(11) DEFAULT 0 COMMENT '사은품 금액 (또는 본사사은품 금액)',
  `ADD_GIFT_AMOUNT` int(11) DEFAULT 0 COMMENT '추가 사은품 금액',
  `PAY_SCHED_DATE` date DEFAULT NULL COMMENT '지급 예정일',
  `PAY_SOURCE` varchar(50) DEFAULT NULL COMMENT '지급처 (지급처 선택 박스 반영)',
  `BANK_NAME` varchar(50) DEFAULT NULL COMMENT '지급 은행명',
  `ACCOUNT_NO` varchar(255) DEFAULT NULL COMMENT '계좌번호 (암호화)',
  `ACCOUNT_HOLDER` varchar(50) DEFAULT NULL COMMENT '예금주',
  `HOLDER_SSN_ENC` varchar(255) DEFAULT NULL COMMENT '주민번호 (암호화)',
  `IS_SAME_AS_BANK` char(1) DEFAULT 'N' COMMENT '위 은행과 동일 체크 여부 (Y/N)',
  `REMARK` text DEFAULT NULL COMMENT '비고',
  `USE_YN` char(1) DEFAULT 'Y' COMMENT '사용 여부 (Y/N)',
  `CREATED_AT` datetime DEFAULT current_timestamp() COMMENT '등록 일시',
  `UPDATED_AT` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp() COMMENT '수정 일시',
  PRIMARY KEY (`GIFT_ID`),
  KEY `FK_GIFT_CUST` (`CUST_ID`),
  CONSTRAINT `FK_GIFT_CUST` FOREIGN KEY (`CUST_ID`) REFERENCES `TB_CUSTOMER` (`CUST_ID`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_uca1400_ai_ci COMMENT='고객 사은품 및 본사 사은품 통합 관리 테이블';
